script.text:
      /* <flatten type="Javascript"> */
function init$VoucherFilter$(f) {f.getItem('so_ct')._idle = &IdleLookupFilter;;}
function active$VoucherFilter$(f) {
  f.add_onResponseComplete(on$Filter$ResponseComplete);
  f._looking = f.getItem('so_ct')._controlBehavior;
  f._looking.add_loading(onclick$VoucherFilter$Before$Loading);
  onChange$Filter$Unit(f.getItem('ma_dvcs'););
}
function close$VoucherFilter$(f) {
  try {f._looking.remove_loading(on$VoucherFilter$Before$Loading);} catch (ex) {}
  try {f.remove_onResponseComplete(on$Filter$ResponseComplete);} catch (ex) {}
}
function on$Filter$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result, g = f.grid;
  switch (context) {
    case 'Checking':
      var k = [];
      g._$u = f.getItemValue('ma_dvcs'), g._$t = f.getItemValue('type'), g._$s = f.getItemValue('ma_kho');
      g._alterTitle = [null, [['%s', f.getItemValue('so_ct').toUpperCase(), true]]];
      break;
    default:
      break;
  }
}
function onclick$VoucherFilter$Before$Loading(sender, e) {
  var f = sender._element.parentForm;
  if ((!f.validFields('ngay_ct1')) || (!f.validFields('ngay_ct2'))) e.type.cancelEvent = true;
  else {
    var g = f.grid, w = g.get_element().parentForm;
    var d1 = f.getItemValue('ngay_ct1'), d2 = f.getItemValue('ngay_ct2');
    a = [
      {Name: 'd1', Type: 'DateTime', Value: d1},
      {Name: 'd2', Type: 'DateTime', Value: d2}
    ];
    sender.set_memvars(a);
  }
}
function onChange$Filter$Unit(o) {o.parentForm.setReferenceKeyFilter('ma_kho');}
/* </flatten> */
